@code {
    private AppointmentModel model = new();
    private EditContext editContext = default!;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isProcessing;
    private bool isBooked;

    private List<DoctorInfo> doctors = [];
    private List<string> availableSlots = [];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate only step-1 fields
        var isValid = editContext.Validate();
        if (!isValid)
            return;

        // Check that step-1 fields specifically are valid
        var step1Fields = new[] { "PatientName", "Email", "Phone", "InsuranceProvider" };
        var hasStep1Errors = step1Fields
            .Any(f => editContext.GetValidationMessages(editContext.Field(f)).Any());

        if (hasStep1Errors)
            return;

        showStep2 = true;
    }

    private void BackToStep1()
    {
        showStep2 = false;
    }

    private async Task OnDoctorOrDateChanged()
    {
        if (!string.IsNullOrEmpty(model.Doctor) && model.Date.HasValue)
        {
            availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(
                model.Doctor, DateOnly.FromDateTime(model.Date.Value));
            // Clear time slot if the previously selected one is no longer available
            if (!availableSlots.Contains(model.TimeSlot ?? ""))
            {
                model.TimeSlot = "";
            }
        }
    }

    private async Task HandleSubmit()
    {
        customValidator?.ClearErrors();
        var isValid = editContext.Validate();
        if (!isValid)
            return;

        isProcessing = true;
        try
        {
            var errors = await AppointmentSvc.ValidatePatientAsync(
                model.Email!, model.InsuranceProvider!, model.Doctor!, model.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            isBooked = true;
        }
        finally
        {
            isProcessing = false;
        }
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_3f2263ce2e3c4b4abde8bf3182a579c8.Components.Pages;

public class AppointmentModel : IValidatableObject
{
    [Required(ErrorMessage = "Patient name is required.")]
    public string? PatientName { get; set; }

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Enter a valid email address.")]
    public string? Email { get; set; }

    [Required(ErrorMessage = "Phone number is required.")]
    public string? Phone { get; set; }

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string? InsuranceProvider { get; set; }

    public string? Doctor { get; set; }

    public DateTime? Date { get; set; }

    public string? TimeSlot { get; set; }

    [MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters.")]
    public string? Reason { get; set; }

    public IEnumerable<ValidationResult> Validate(ValidationContext validationContext)
    {
        // Step-2 fields are only required when they're being submitted
        // We check if Doctor is set to determine we're in step 2
        if (Doctor is null && Date is null && TimeSlot is null && Reason is null)
            yield break;

        if (string.IsNullOrWhiteSpace(Doctor))
            yield return new ValidationResult("Please select a doctor.", [nameof(Doctor)]);

        if (!Date.HasValue)
            yield return new ValidationResult("Appointment date is required.", [nameof(Date)]);
        else if (Date.Value.Date <= DateTime.Today)
            yield return new ValidationResult("Date must be in the future.", [nameof(Date)]);

        if (string.IsNullOrWhiteSpace(TimeSlot))
            yield return new ValidationResult("Please select a time slot.", [nameof(TimeSlot)]);

        if (string.IsNullOrWhiteSpace(Reason))
            yield return new ValidationResult("Reason for visit is required.", [nameof(Reason)]);
    }
}

