+        // Step-2 fields are only required when they're being submitted
+        // We check if Doctor is set to determine we're in step 2
+        if (Doctor is null && Date is null && TimeSlot is null && Reason is null)
+            yield break;
+
+        if (string.IsNullOrWhiteSpace(Doctor))
+            yield return new ValidationResult("Please select a doctor.", [nameof(Doctor)]);
+
+        if (!Date.HasValue)
+            yield return new ValidationResult("Appointment date is required.", [nameof(Date)]);
