+            yield return new ValidationResult("Date must be in the future.", [nameof(Date)]);
+
+        if (string.IsNullOrWhiteSpace(TimeSlot))
+            yield return new ValidationResult("Please select a time slot.", [nameof(TimeSlot)]);
