toolArgs.file_text:
@page "/book-appointment"
@rendermode InteractiveServer
@using sv_3f2263ce2e3c4b4abde8bf3182a579c8.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm EditContext="editContext" OnSubmit="HandleSubmit" FormName="book-appointment">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    <h2>Patient Information</h2>

    <div class="mb-3">
        <label class="form-label">Patient Name</label>
        <InputText class="form-control" @bind-Value="model.PatientName" />
        <ValidationMessage For="() => model.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="model.Email" />
        <ValidationMessage For="() => model.Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="model.Phone" />
        <ValidationMessage For="() => model.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label">Insurance Provider</label>
        <InputSelect class="form-control" @bind-Value="model.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => model.InsuranceProvider" />
    </div>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2" disabled="@isProcessing">
            @(isProcessing ? "Validating..." : "Next")
        </button>
    }

    @if (showStep2)
    {
        <hr />
        <h2>Appointment Details</h2>

        <div class="mb-3">
            <label class="form-label">Preferred Doctor</label>
            <InputSelect class="form-control" @bind-Value="model.Doctor" @bind:after="OnDoctorOrDateChanged">
                <option value="">-- Select --</option>
                @foreach (var doc in doctors)
                {
                    <option value="@doc.Name">@doc.Name</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.Doctor" />
        </div>

        <div class="mb-3">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="model.Date" @bind:after="OnDoctorOrDateChanged" />
            <ValidationMessage For="() => model.Date" />
        </div>

        <div class="mb-3">
            <label class="form-label">Time Slot</label>
            <InputSelect class="form-control" @bind-Value="model.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in availableSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.TimeSlot" />
        </div>

        <div class="mb-3">
            <label class="form-label">Reason for Visit</label>
            <InputTextArea class="form-control" @bind-Value="model.Reason" rows="3" />
            <ValidationMessage For="() => model.Reason" />
        </div>

        <button type="button" class="btn btn-secondary me-2" @onclick="BackToStep1">Back</button>
        <button type="submit" class="btn btn-success" disabled="@isProcessing">
            @(isProcessing ? "Checking Availability..." : "Check Availability")
        </button>
    }
</EditForm>

@if (isBooked)
{
    <div class="alert alert-success mt-3">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentModel model = new();
    private EditContext editContext = default!;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isProcessing;
    private bool isBooked;

    private List<DoctorInfo> doctors = [];
    private List<string> availableSlots = [];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate only step-1 fields
        var isValid = editContext.Validate();
        if (!isValid)
            return;

        // Check that step-1 fields specifically are valid
        var step1Fields = new[] { "PatientName", "Email", "Phone", "InsuranceProvider" };
        var hasStep1Errors = step1Fields
            .Any(f => editContext.GetValidationMessages(editContext.Field(f)).Any());

        if (hasStep1Errors)
            return;

        showStep2 = true;
    }

    private void BackToStep1()
    {
        showStep2 = false;
    }

    private async Task OnDoctorOrDateChanged()
    {
        if (!string.IsNullOrEmpty(model.Doctor) && model.Date.HasValue)
        {
            availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(
                model.Doctor, DateOnly.FromDateTime(model.Date.Value));
            // Clear time slot if the previously selected one is no longer available
            if (!availableSlots.Contains(model.TimeSlot ?? ""))
            {
                model.TimeSlot = "";
            }
        }
    }

    private async Task HandleSubmit()
    {
        customValidator?.ClearErrors();
        var isValid = editContext.Validate();
        if (!isValid)
            return;

        isProcessing = true;
        try
        {
            var errors = await AppointmentSvc.ValidatePatientAsync(
                model.Email!, model.InsuranceProvider!, model.Doctor!, model.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            isBooked = true;
        }
        finally
        {
            isProcessing = false;
        }
    }
}

